var myHeaders = new Headers();
myHeaders.append("accept", "application/json");
myHeaders.append("content-type", "application/json");
myHeaders.append("x-api-key", "{{X-API-KEY}}");
myHeaders.append("x-tenant", "{{X-TENANT}}");

var raw = JSON.stringify({
   "id": "",
   "slug": "",
   "language_translation": [
      {}
   ],
   "name": "",
   "address": "",
   "post_code": "",
   "country_code": "",
   "country": "",
   "state": "",
   "city": "",
   "phone": "",
   "email": "",
   "merchant_category_ids": [],
   "accepted_order_types": [],
   "status": 0,
   "delivery_by": "",
   "owner_name": "",
   "owner_phone": "",
   "commission": {
      "type": "",
      "value": "",
      "calculate_on_status": 0
   },
   "tax_method": "",
   "type": ""
});

var requestOptions = {
   method: 'POST',
   headers: myHeaders,
   body: raw,
   redirect: 'follow'
};

fetch("https://api.hyperzod.app/admin/v1/merchant/update", requestOptions)
   .then(response => response.text())
   .then(result => console.log(result))
   .catch(error => console.log('error', error));

